formulas.expression:
IF(
  CONTAINS({!Next_Stage_Selected_Calculation}, "Close Lost"),
  "Closed Lost",
  IF(
    CONTAINS({!Next_Stage_Selected_Calculation}, "Close Won"),
    "Closed Won",
  {!Next_Stage_Selected_Calculation}
  )
)

IF( AND( CONTAINS({!Next_Stage_Selected_Calculation}, "Close Won"), OR( ISBLANK({!Assignment_Champion1}), ISBLANK({!Assignment_Champion2}), ISBLANK({!Assignment_Identify_Pain1}), ISBLANK({!Assignment_Identify_Pain2}), ISBLANK({!Assignment_Identify_Pain3}), ISBLANK({!Assignment_DC2}), ISBLANK({!Assignment_DC1}), ISBLANK({!Get_Opportunity.Identify_Pain__c}), ISBLANK({!Get_Opportunity.Decision_Criteria__c}), ISBLANK(TEXT({!Get_Opportunity.Competition__c})), AND( ISBLANK({!Get_Opportunity.Competitor_Product__c}), OR( TEXT({!Get_Opportunity.Competition__c})='Evaluating a competitor', TEXT({!Get_Opportunity.Competition__c})='Currently using a competitor', TEXT({!Get_Opportunity.Competition__c})='Will replace SW with a competitor')), AND(ISBLANK({!Get_Opportunity.Other_Competitors__c}) ,INCLUDES({!Get_Opportunity.Competitor_Product__c},"Other"))
, ISBLANK({!Assignment_DP2}), ISBLANK({!Assignment_DP1}), ISBLANK({!Assignment_Economic_Buyer1}), ISBLANK({!Assignment_Economic_Buyer2}), ISBLANK({!Assignment_Metrics1}), ISBLANK({!Assignment_Metrics2}), ISBLANK({!Get_Opportunity.Decision_Process__c}), ISBLANK({!Get_Opportunity.Economic_Buyer__c}), ISBLANK({!Get_Opportunity.Metrics__c}), ISBLANK({!Assignment_Paper2}), ISBLANK({!Assignment_paper1}), ISBLANK({!Get_Opportunity.Paper_Process__c})
)), true, false )

IF( OR( AND ({!Update_Stage_On_Opportunity.value} = true , NOT(AND({!Next_Stage_Select_Sales_Qualified}={!Close_Lost},TEXT({!Get_Opportunity.StageName})='Initial Discovery')), OR( TEXT({!Get_Opportunity.Cycle__c}) = '', ISBLANK({!Get_Opportunity.Cycle_Price_Local__c}) , {!Get_Opportunity.Cycle_Price_Local__c} = 0, AND({!Next_Stage_Select_Contract}={!Contracts}, {!Get_Opportunity.Decision_Maker__c} = false)
))
), true, false )
